import numpy as np

def transform_grid(grid: np.ndarray) -> np.ndarray:
    g = grid.copy()
    colors = [c for c in np.unique(g) if c != 0]
    for c in colors:
        coords = np.argwhere(g == c)
        if coords.size == 0:
            continue
        # fill horizontal gaps inside each row segment
        for r in np.unique(coords[:, 0]):
            cols = np.where(g[r] == c)[0]
            if len(cols) >= 2:
                g[r, cols.min():cols.max()+1] = c
    # then shift the whole colored pattern right by one if there is room
    out = np.zeros_like(g)
    for c in colors:
        coords = np.argwhere(g == c)
        if coords.size == 0:
            continue
        if coords[:, 1].max() < g.shape[1] - 1:
            coords = coords.copy()
            coords[:, 1] += 1
        out[coords[:, 0], coords[:, 1]] = c
    return out

# candidate 1
import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    g = np.array(input_grid, copy=True)
    h, w = g.shape
    vals = [v for v in np.unique(g) if v != 0]
    if len(vals) < 2:
        return g
    vals = sorted(vals)
    for v in vals:
        pos = np.argwhere(g == v)
        if pos.size == 0:
            continue
        r, c = pos[0]
        if np.count_nonzero(g[r, :]) == 1:
            g[r, :] = v
        elif np.count_nonzero(g[:, c]) == 1:
            g[:, c] = v
    return g

