import numpy as np

def transform_grid(grid: np.ndarray) -> np.ndarray:
    g = np.array(grid, copy=True)
    vals = [v for v in np.unique(g) if v != 0]
    if not vals:
        return g
    for v in vals:
        coords = np.argwhere(g == v)
        if coords.size == 0:
            continue
        r, c = coords[0]
        row_has = np.count_nonzero(g[r] != 0)
        col_has = np.count_nonzero(g[:, c] != 0)
        if row_has == 1:
            g[r, :] = v
        elif col_has == 1:
            g[:, c] = v
    return g

