import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    g = np.array(input_grid)
    row_counts = np.sum(g != 0, axis=1)
    col_counts = np.sum(g != 0, axis=0)
    rmask = row_counts > 0
    cmask = col_counts > 0
    if not np.any(rmask) or not np.any(cmask):
        return g.copy()
    r = np.where(rmask)[0]
    c = np.where(cmask)[0]
    return g[r.min():r.max()+1, c.min():c.max()+1].copy()

