import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    mapping = {1: 5, 2: 6, 3: 4, 4: 3, 5: 1, 6: 2, 8: 9, 9: 8}
    out = np.vectorize(lambda x: mapping.get(int(x), int(x)))(input_grid)
    return out.astype(int)

