import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    g = np.array(input_grid, dtype=int)
    out = np.zeros_like(g)
    nz = np.argwhere(g != 0)
    if nz.size == 0:
        return out
    vals = g[g != 0]
    colors, counts = np.unique(vals, return_counts=True)
    color = colors[np.argmax(counts)]
    pts = np.argwhere(g == color)
    if len(pts) == 0:
        return out
    r0, c0 = pts.min(axis=0)
    r1, c1 = pts.max(axis=0)
    h = r1 - r0 + 1
    w = c1 - c0 + 1
    # infer diagonal direction from the non-background pattern
    if h == 1 and w == 1:
        out[:] = 0
        out[0, :] = color
        return out
    if h <= w:
        # down-right diagonal band
        for i in range(g.shape[0]):
            for j in range(g.shape[1]):
                if 0 <= j - i < w:
                    out[i, j] = color
    else:
        # up-right diagonal band
        for i in range(g.shape[0]):
            for j in range(g.shape[1]):
                if 0 <= j + i - (g.shape[0] - 1) < w:
                    out[i, j] = color
    return out

