    g = np.array(input_grid, copy=True)
    h, w = g.shape
    rows2 = np.where(np.any(g == 2, axis=1))[0]
    cols8 = np.where(np.any(g == 8, axis=0))[0]
    for r in rows2:
        for c in cols8:
            if r < h:
                g[r:, c] = 8
    return g

