import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    g = np.array(input_grid)
    h, w = g.shape
    out = np.zeros((h * 2, w * 2), dtype=int)
    for i in range(h):
        for j in range(w):
            v = g[i, j]
            if v == 0:
                out[2*i:2*i+2, 2*j:2*j+2] = 8
            else:
                out[2*i:2*i+2, 2*j:2*j+2] = np.array([[v, 8], [8, v]])
    return out

