import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    g = input_grid.copy()
    h, w = g.shape
    color = 3
    for r in range(h - 1):
        for c in range(w - 1):
            block = g[r:r+2, c:c+2]
            if np.count_nonzero(block) == 4:
                if 0 not in block:
                    continue
                if np.any(block == 3):
                    continue
                vals = block.flatten()
                if len(set(vals.tolist())) == 2:
                    g[r:r+2, c:c+2] = color
    return g

